<span class="line">    weatherDescriptions<span class="token punctuation">[</span>weather<span class="token punctuation">.</span>weathercode<span class="token punctuation">]</span> <span class="token operator">||</span> <span class="token string">&quot;Unknown Condition&quot;</span><span class="token punctuation">;</span></span>
